mapper.select:
SELECT 
    wo.*,
    fd.device_code,
    fd.device_name,
    cu.real_name AS creator_name,
    au.real_name AS assignee_name,
    pu.real_name AS processor_name,
    ru.real_name AS reviewer_name
FROM device_work_order wo
LEFT JOIN factory_device fd ON wo.device_id = fd.device_id
LEFT JOIN sys_user cu ON wo.creator_id = cu.id
LEFT JOIN sys_user au ON wo.assignee_id = au.id
LEFT JOIN sys_user pu ON wo.processor_id = pu.id
LEFT JOIN sys_user ru ON wo.reviewer_id = ru.id


        AND wo.order_code LIKE CONCAT(#{bo.orderCode}, '%')


        AND wo.device_id = #{bo.deviceId}


        AND wo.alarm_id = #{bo.alarmId}


        AND wo.order_type = #{bo.orderType}


        AND wo.order_source = #{bo.orderSource}


        AND wo.priority = #{bo.priority}


        AND wo.creator_id = #{bo.creatorId}


        AND wo.assignee_id = #{bo.assigneeId}


        AND wo.order_status = #{bo.orderStatus}


ORDER BY wo.create_time DESC
